// MAIN PROGRAM EXECUTION
MAIN_PROGRAM:
    WHILE TRUE DO
        EXECUTE_INSTRUCTION()
        IF INTERRUPT_PENDING THEN
            CALL_HANDLE_INTERRUPT()
        END IF
    END WHILE

// INTERRUPT HANDLER
PROCEDURE HANDLE_INTERRUPT()
    // Save current process state
    PUSH(PC)                   // Save Program Counter
    PUSH(FLAGS)                // Save processor flags
    PUSH(REGISTERS)            // Save all general purpose registers

    // Disable further interrupts
    INTERRUPT_ENABLE = FALSE

    // Get interrupt vector address
    INT_VECTOR = GET_INTERRUPT_VECTOR()

    // Load address of ISR (Interrupt Service Routine)
    PC = INT_VECTOR

    // Execute interrupt service routine
    EXECUTE_ISR()

    // Restore process state
    POP(REGISTERS)
    POP(FLAGS)
    POP(PC)

    // Re-enable interrupts
    INTERRUPT_ENABLE = TRUE

    RETURN_TO_INTERRUPTED_PROGRAM()
END PROCEDURE

#include <stdio.h>
#include <unistd.h>
#include <sys/syscall.h>

// Simple example showing system call flow
// In practice, libc wrapper functions are used

int main() {
    // User mode code
    char buffer[100];
    int fd;  // file descriptor

    // Open file - this triggers a system call
    // Internally: syscall(SYS_open, filename, flags, mode)
    fd = open("test.txt", O_RDONLY);

    if (fd < 0) {
        perror("Open failed");
        return 1;
    }

    // Read from file - triggers system call
    // Internally: syscall(SYS_read, fd, buffer, count)
    ssize_t bytes_read = read(fd, buffer, sizeof(buffer));

    if (bytes_read > 0) {
        buffer[bytes_read] = '\0';
        printf("Read %zd bytes: %s\n", bytes_read, buffer);
    }

    // Close file - triggers system call
    close(fd);

    return 0;
}

/*
 * How the system call works internally:
 * 1. User program calls read() from libc
 * 2. libc prepares arguments in specific registers
 * 3. libc executes 'syscall' instruction (transition to kernel mode)
 * 4. CPU saves user state and switches to kernel mode
 * 5. Kernel executes the file read operation
 * 6. Control returns to user space with result
 */
